#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to database and perform operations
    auto result = sqlite::connect("test_db.sqlite")
        .and_then(drop_table<Product> | if_exists)
        .and_then(create_table<Product>)
        .and_then(begin_transaction)
        .and_then([&products](auto&& conn) {
            // Insert each product
            for (const auto& product : products) {
                auto insert_result = conn.execute(insert(product));
                if (!insert_result) {
                    return insert_result; // This will break the chain and trigger rollback
                }
            }
            return conn.execute(commit);
        })
        .map_error([](auto&& error) {
            // If any error occurs, transaction will be automatically rolled back
            // due to the RAII nature of the connection
            return error;
        });

    return result.is_ok();
}

}  // namespace batch_insert_products
```

