#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  struct Student {
    sqlgen::PrimaryKey<std::string> SNo;
    std::string SName;
    std::optional<int> Sex = 1;
    std::optional<std::string> Birthday;
    std::optional<int> Major;
    float Scorses = 0.0f;
    std::optional<std::string> Remark;
  };

  struct Course {
    sqlgen::PrimaryKey<sqlgen::AutoIncrement<int>> CID;
    std::string CName;
    std::optional<int> Term = 1;
    std::optional<int> CTime;
    float Credit = 0.0f;
  };

  struct Score {
    std::string SNo;
    int CID;
    std::optional<float> Score;

    // Define composite primary key
    struct PrimaryKey {
      std::string SNo;
      int CID;

      REFLECT(PrimaryKey, SNo, CID)
    };

    PrimaryKey primary_key() const { return {SNo, CID}; }

    // Define foreign key relationships
    sqlgen::ForeignKey<Student> student_fk{SNo};
    sqlgen::ForeignKey<Course> course_fk{CID};
  };

  void design_eas_database() {
    // Remove existing database file if it exists
    std::filesystem::remove("test_db.sqlite");

    // Connect to SQLite database
    sqlgen::Database<sqlgen::SQLite> db("test_db.sqlite");

    // Create tables
    db.create_table<Student>();
    db.create_table<Course>();
    db.create_table<Score>();
  }

}
