Here's the complete implementation of the function using the `sqlgen` library:

```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to database and create tables
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(create_table<Course> | if_not_exists)
    .and_then(create_table<Enrollment> | if_not_exists)
    .and_then([](auto conn) {
      // Build the query using sqlgen's query builder
      auto query = select(
        columns(&Course::title, 
                count(&Enrollment::enrollment_id).as("student_count"),
                avg(&Enrollment::grade).as("avg_grade"))
      ).from<Course>()
       .left_join<Enrollment>(on(&Course::course_id == &Enrollment::course_id))
       .group_by(&Course::course_id, &Course::title);

      return query | conn;
    })
    .and_then(read<std::vector<CourseStatsView>>);

  if (result) {
    // Convert CourseStatsView to CourseStats
    std::vector<CourseStatsView> views = result.value();
    std::vector<CourseStats> stats;
    stats.reserve(views.size());

    for (const auto& view : views) {
      stats.push_back(CourseStats{
        .title = view.title,
        .student_count = view.student_count,
        .avg_grade = view.avg_grade
      });
    }

    return stats;
  }

  // Return empty vector if there was an error
  return {};
}

}  // namespace query_course_enrollment_stats
