Looking at the code fragments and the requirements, I'll implement the function using `sqlgen`'s dynamic query building capabilities. Here's the complete implementation:

```cpp
#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Start with base SELECT query
    auto query = select<Book>;

    // Build WHERE conditions dynamically based on provided filters
    if (filters.title_keyword || filters.min_year || filters.genre || filters.max_price) {
        auto condition = sqlgen::condition(true); // Start with a true condition

        if (filters.title_keyword) {
            condition = condition and_ ("title"_c.like("%" + *filters.title_keyword + "%"));
        }

        if (filters.min_year) {
            condition = condition and_ ("year"_c >= *filters.min_year);
        }

        if (filters.genre) {
            condition = condition and_ ("genre"_c == *filters.genre);
        }

        if (filters.max_price) {
            condition = condition and_ ("price"_c <= *filters.max_price);
        }

        query = query | where(condition);
    }

    // Execute the query
    auto result = sqlgen::sqlite::connect("test_db.sqlite")
                     .and_then(query)
                     .and_then(read<std::vector<Book>>);

    // Return results or empty vector on error
    if (result.is_ok()) {
        return result.value();
    } else {
        return std::vector<Book>{};
    }
}

}  // namespace query_search_books_by_criteria
```

Key implementation details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to connect to the SQLite database
2. **Dynamic Query Building**: Starts with `select<Book>` and conditionally adds WHERE clauses using the `| where(condition)` syntax
3. **Condition Construction**: Builds conditions dynamically using `and_` operator, only adding clauses when parameters are provided
4. **LIKE Operator**: Uses `"title"_c.like("%" + *filters.title_keyword + "%")` for partial title matching
5. **Comparison Operators**: Uses standard comparison operators (`>=`, `==`, `<=`) for numeric and equality comparisons
6. **Error Handling**: Returns an empty vector if the query fails, but you could modify this to throw exceptions or return `std::optional` based on your error handling preferences

The implementation follows the patterns shown in the code fragments, particularly the use of:
- `select<Book>` for the base query
- `where(condition)` for filtering
- Column references using the `_c` literal (e.g., `"title"_c`)
- The `and_` operator for combining conditions
- The monadic `and_then()` pattern for chaining operations

