#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct MutualFriendsResult {
  std::string username1;
  std::string username2;
  int mutual_friends_count;
};

struct UserFriendCount {
  std::string username;
  int friend_count;
};

struct FriendRecommendation {
  std::string user1_name;
  std::string user2_name;
  std::string city;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen;
    using namespace sqlgen::sqlite;

    // Create database connection
    auto db = Database::connect(":memory:");

    // Create tables
    db.execute(CreateTable<User>{});
    db.execute(CreateTable<Friendship>{});

    // Insert users
    for (const auto& user : users) {
        db.execute(InsertInto<User>{user});
    }

    // Insert friendships
    for (const auto& friendship : friendships) {
        db.execute(InsertInto<Friendship>{friendship});
    }

    std::vector<FriendConnection> results;

    // 1. Find mutual friends using SELF-JOIN
    {
        auto mutual_friends_query = Select{
            Column<User, &User::username>{}.as("user1_name"),
            Column<User, &User::username>{}.as("user2_name")
        }.from<User>("u1")
         .inner_join<Friendship>("f1").on(Column<User, &User::user_id>{"u1"} == Column<Friendship, &Friendship::user1_id>{"f1"})
         .inner_join<Friendship>("f2").on(Column<Friendship, &Friendship::user_id2>{"f1"} == Column<Friendship, &Friendship::user_id1>{"f2"})
         .inner_join<User>("u2").on(Column<Friendship, &Friendship::user_id2>{"f2"} == Column<User, &User::user_id>{"u2"})
         .where(Column<User, &User::user_id>{"u1"} < Column<User, &User::user_id>{"u2"})
         .group_by(Column<User, &User::user_id>{"u1"}, Column<User, &User::user_id>{"u2"})
         .having(Count(Column<Friendship, &Friendship::user_id2>{"f1"}) > 0);

        auto mutual_friends = db.execute(mutual_friends_query);
        for (const auto& row : mutual_friends) {
            results.push_back(FriendConnection{
                .user1_name = row.get<"user1_name">(),
                .user2_name = row.get<"user2_name">()
            });
        }
    }

    // 2. Find users with more than average number of friends using nested query
    {
        auto avg_friends_subquery = Select{Count(Column<Friendship, &Friendship::user1_id>{}).as("friend_count")}
            .from<Friendship>()
            .group_by(Column<Friendship, &Friendship::user_id1>{});

        auto popular_users_query = Select{
            Column<User, &User::username>{},
            Count(Column<Friendship, &Friendship::user_id2>{}).as("friend_count")
        }.from<User>()
         .left_join<Friendship>().on(Column<User, &User::user_id>{} == Column<Friendship, &Friendship::user_id1>{})
         .group_by(Column<User, &User::user_id>{}, Column<User, &User::username>{})
         .having(Count(Column<Friendship, &Friendship::user_id2>{}) > 
                Select{Avg(Column<"friend_count">{})}.from(avg_friends_subquery))
         .order_by(Count(Column<Friendship, &Friendship::user_id2>{}).desc());

        auto popular_users = db.execute(popular_users_query);
        for (const auto& row : popular_users) {
            results.push_back(FriendConnection{
                .user1_name = row.get<"username">(),
                .user2_name = "has " + std::to_string(row.get<"friend_count">()) + " friends"
            });
        }
    }

    // 3. Find friend-of-friend relationships (people connected through exactly one mutual friend)
    {
        auto friend_of_friend_query = Select{
            Column<User, &User::username>{}.as("user1_name"),
            Column<User, &User::username>{}.as("user2_name")
        }.from<User>("u1")
         .inner_join<Friendship>("f1").on(Column<User, &User::user_id>{"u1"} == Column<Friendship, &Friendship::user_id1>{"f1"})
         .inner_join<Friendship>("f2").on(Column<Friendship, &Friendship::user_id2>{"f1"} == Column<Friendship, &Friendship::user_id1>{"f2"})
         .inner_join<User>("u2").on(Column<Friendship, &Friendship::user_id2>{"f2"} == Column<User, &User::user_id>{"u2"})
         .where(Column<User, &User::user_id>{"u1"} != Column<User, &User::user_id>{"u2"})
         .where_not_exists(
            Select{1}.from<Friendship>("f3")
            .where(Column<Friendship, &Friendship::user_id1>{"f3"} == Column<User, &User::user_id>{"u1"})
            .where(Column<Friendship, &Friendship::user_id2>{"f3"} == Column<User, &User::user_id>{"u2"})
         );

        auto fof_relationships = db.execute(friend_of_friend_query);
        for (const auto& row : fof_relationships) {
            results.push_back(FriendConnection{
                .user1_name = row.get<"user1_name">(),
                .user2_name = row.get<"user2_name">() + " (friend-of-friend)"
            });
        }
    }

    // 4. Count friends per user and identify most connected users
    {
        auto friend_count_query = Select{
            Column<User, &User::username>{},
            Count(Column<Friendship, &Friendship::user_id2>{}).as("friend_count")
        }.from<User>()
         .left_join<Friendship>().on(Column<User, &User::user_id>{} == Column<Friendship, &Friendship::user_id1>{})
         .group_by(Column<User, &User::user_id>{}, Column<User, &User::username>{})
         .order_by(Count(Column<Friendship, &Friendship::user_id2>{}).desc());

        auto friend_counts = db.execute(friend_count_query);
        for (const auto& row : friend_counts) {
            results.push_back(FriendConnection{
                .user1_name = row.get<"username">(),
                .user2_name = "Friend count: " + std::to_string(row.get<"friend_count">())
            });
        }
    }

    // 5. Find users in the same city who are not yet friends (recommendation)
    {
        auto recommendation_query = Select{
            Column<User, &User::username>{}.as("user1_name"),
            Column<User, &User::username>{}.as("user2_name"),
            Column<User, &User::city>{}.as("city")
        }.from<User>("u1")
         .inner_join<User>("u2").on(Column<User, &User::city>{"u1"} == Column<User, &User::city>{"u2"})
         .where(Column<User, &User::user_id>{"u1"} < Column<User, &User::user_id>{"u2"})
         .where(Column<User, &User::city>{"u1"}.is_not_null())
         .where_not_exists(
            Select{1}.from<Friendship>("f")
            .where((Column<Friendship, &Friendship::user_id1>{"f"} == Column<User, &User::user_id>{"u1"} 
                   && Column<Friendship, &Friendship::user_id2>{"f"} == Column<User, &User::user_id>{"u2"})
                   || (Column<Friendship, &Friendship::user_id1>{"f"} == Column<User, &User::user_id>{"u2"} 
                   && Column<Friendship, &Friendship::user_id2>{"f"} == Column<User, &User::user_id>{"u1"}))
         );

        auto recommendations = db.execute(recommendation_query);
        for (const auto& row : recommendations) {
            results.push_back(FriendConnection{
                .user1_name = row.get<"user1_name">(),
                .user2_name = row.get<"user2_name">() + " (same city: " + row.get<"city">() + ")"
            });
        }
    }

    return results;
}

}  // namespace analyze_social_network
