```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <cstdio>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Remove existing database file if it exists
  std::remove("test_db.sqlite");

  JoinAnalysis analysis;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(create_table<Department> | if_not_exists)
    .and_then(create_table<Employee> | if_not_exists)
    .and_then(insert_range(depts))
    .and_then(insert_range(emps));

  if (!conn) {
    return analysis; // Return empty analysis if connection fails
  }

  // 1. INNER JOIN - employees with assigned departments
  auto inner_join_query = R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    INNER JOIN Employee e ON d.department_id = e.department_id
  )"_sql;

  auto inner_results = conn.and_then(inner_join_query)
                          .and_then(read<std::vector<JoinResult>>);
  if (inner_results) {
    analysis.inner_join_results = std::move(*inner_results);
  }

  // 2. LEFT JOIN - all employees (even without departments)
  auto left_join_query = R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
  )"_sql;

  auto left_results = conn.and_then(left_join_query)
                         .and_then(read<std::vector<JoinResult>>);
  if (left_results) {
    analysis.left_join_results = std::move(*left_results);
  }

  // 3. RIGHT JOIN - all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN directly, so we simulate it with LEFT JOIN
  auto right_join_query = R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
  )"_sql;

  auto right_results = conn.and_then(right_join_query)
                          .and_then(read<std::vector<JoinResult>>);
  if (right_results) {
    analysis.right_join_results = std::move(*right_results);
  }

  // 4. FULL JOIN - all employees and departments
  // SQLite doesn't support FULL JOIN directly, so we simulate it with UNION
  auto full_join_query = R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
    UNION
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
    WHERE e.employee_id IS NULL
  )"_sql;

  auto full_results = conn.and_then(full_join_query)
                         .and_then(read<std::vector<JoinResult>>);
  if (full_results) {
    analysis.full_join_results = std::move(*full_results);
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

This implementation:

1. **Connects to SQLite database**: Creates/connects to "test_db.sqlite" and removes any existing file first
2. **Creates tables**: Uses `create_table` with `if_not_exists` modifier for both Department and Employee tables
3. **Inserts data**: Uses `insert_range` to insert the provided department and employee data
4. **Performs join operations**:
   - **INNER JOIN**: Gets only employees with assigned departments
   - **LEFT JOIN**: Includes all employees (even those without departments)
   - **RIGHT JOIN**: Simulated using LEFT JOIN with tables swapped (since SQLite doesn't support RIGHT JOIN directly)
   - **FULL JOIN**: Simulated using UNION of LEFT JOINs (since SQLite doesn't support FULL JOIN directly)
5. **Returns comprehensive analysis**: Populates the JoinAnalysis struct with results from all join types

The code follows the patterns shown in the provided code fragments, using the `sqlgen` library's fluent interface for database operations and the `_sql` literal for SQL queries.

