Here's the complete implementation of the `concat_function`:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace concat_function {

struct Person {
  sqlgen::PrimaryKey<int> id;
  std::string first_name;
  std::string last_name;
};

struct FullName {
  std::string full_name;
};

/**
 * This function demonstrates CONCAT usage.
 * Returns: query value.
 */
inline auto concat_function() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Construct a query to select CONCAT(first_name, ' ', last_name) as full_name
    return select(concat("first_name"_c, " "_s, "last_name"_c).as("full_name")).from<Person>();
}

}  // namespace concat_function
```

This implementation:

1. Uses the `sqlgen::concat()` function to concatenate the first name, a space, and the last name
2. Uses column references with `"_c"` suffix and string literals with `"_s"` suffix
3. Aliases the result as "full_name" using `.as("full_name")`
4. Selects from the `Person` table using `.from<Person>()`
5. Returns the constructed query object

The query will generate SQL similar to:
```sql
SELECT CONCAT(first_name, ' ', last_name) AS full_name FROM Person
```

