Here's the complete implementation of the `coalesce_function`:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <optional>

namespace coalesce_function {

struct Profile {
  sqlgen::PrimaryKey<int> id;
  std::optional<std::string> nickname;
};

struct NicknameResult {
  std::string display_name;
};

/**
 * This function demonstrates COALESCE usage.
 * Returns: query value.
 */
inline auto coalesce_function() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Construct a query that uses COALESCE to handle null nicknames
    auto query = sqlgen::read<NicknameResult> | 
                 sqlgen::from<Profile> |
                 sqlgen::select(sqlgen::coalesce("nickname"_c, "Anonymous").as("display_name"));

    // Generate and return the SQL query string
    return sqlite::to_sql(query);
}

}  // namespace coalesce_function
```

This implementation:

1. Uses the `sqlgen::coalesce` function to create a COALESCE expression that will return the nickname if it exists, or 'Anonymous' if it's null
2. Uses the `as()` method to alias the result as "display_name" to match the `NicknameResult` struct
3. Uses `sqlgen::read<NicknameResult>` to specify the result type
4. Uses `sqlgen::from<Profile>` to specify the source table
5. Uses `sqlite::to_sql()` to generate the final SQL query string
6. Returns the generated SQL query as required

The resulting SQL query will look something like:
```sql
SELECT COALESCE(nickname, 'Anonymous') AS display_name FROM Profile
```

