#include <vector>

namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    // Return empty vector if connection fails
    return {};
  }
  auto conn = conn_result.value();

  // Build the query using sqlgen's DSL
  auto query = select(
    "p.product_id"_c, 
    "p.product_name"_c, 
    "p.category"_c, 
    sqlgen::as("total_sales", sqlgen::sum("p.price"_c * "s.quantity"_c))
  )
  .from<Product>("p")
  .join<Sales>("s").on("p.product_id"_c == "s.product_id"_c)
  .group_by("p.product_id"_c, "p.product_name"_c, "p.category"_c)
  .order_by("total_sales"_c.desc())
  .limit(limit_count);

  // Execute the query and return results
  auto result = query.execute(conn);
  if (result) {
    return result.value();
  }

  // Return empty vector if query execution fails
  return {};
}

}  // namespace get_top_products

