```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Create connection to SQLite database
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Use sqlgen to build the query for weekday analysis
  using namespace sqlgen;

  // Create a query that extracts weekday from sale_time and aggregates quantities
  auto query = Select(
      // Extract weekday using SQLite's strftime function (0=Sunday, 6=Saturday)
      expr("strftime('%w', sale_time)").as("weekday"),
      expr("SUM(quantity)").as("total_quantity")
  ).from<Sales>().group_by("weekday").order_by("weekday");

  // Execute the query and get results
  auto results = conn.query<WeekdayStats>(query);

  return results;
}

}  // namespace weekday_sales_analysis
