  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  // Connect to SQLite database
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Build the query using sqlgen expressions
  auto query = sqlgen::sqlite::select(
    sqlgen::columns(
      &Project::project_id,
      &Project::name,
      sqlgen::expr("strftime('%d', {})", &TimeLog::start_time).as("day"),
      sqlgen::expr("strftime('%m', {})", &TimeLog::start_time).as("month"),
      sqlgen::expr("strftime('%Y', {})", &TimeLog::start_time).as("year"),
      sqlgen::expr("strftime('%H', {})", &TimeLog::start_time).as("hour"),
      sqlgen::expr("strftime('%M', {})", &TimeLog::start_time).as("minute"),
      sqlgen::expr("strftime('%S', {})", &TimeLog::start_time).as("second"),
      sqlgen::expr("julianday({}) - julianday({})", &TimeLog::end_time, &TimeLog::start_time).as("duration_days")
    ),
    sqlgen::inner_join<Project, TimeLog>(&Project::project_id, &TimeLog::project_id)
  );

  // Execute the query and return results
  return db.query<TimeMetrics>(query);
}

}  // namespace project_time_tracking
