Based on the code fragments and the requirements, here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create a CREATE TABLE AS SELECT statement
    // Select all records from Source where value > 100
    // and create Target table with the value column
    return create_table_as<Target>(
        select(&Target::value)
            .from<Source>()
            .where("value"_c > 100)
    );
}

}  // namespace create_table_as_select
```

